SELECT

FROM operation_log


        AND operator LIKE CONCAT('%', #{params.operator}, '%')


        AND operation_module = #{params.operationModule}


        AND operation_type = #{params.operationType}


        AND status = #{params.status}


        AND create_time >= #{params.startTime}


        AND create_time <= #{params.endTime}


ORDER BY create_time DESC
LIMIT #{params.offset}, #{params.limit}

SELECT COUNT(1)
FROM operation_log


        AND operator LIKE CONCAT('%', #{params.operator}, '%')


        AND operation_module = #{params.operationModule}


        AND operation_type = #{params.operationType}


        AND status = #{params.status}


        AND create_time >= #{params.startTime}


        AND create_time <= #{params.endTime}
